import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(p1, p2):
        return np.linalg.norm(p1 - p2)

    def time_to_node(start_pos, end_pos, speed):
        distance = calculate_distance(start_pos, end_pos)
        return distance / speed

    best_node = None
    min_time_cost = float('inf')

    for i, customer in enumerate(unvisited_customers):
        travel_time = time_to_node(cur_truck_pos, customer, truck_speed)
        arrival_time = current_time + travel_time
        window_open, window_close = time_windows[i]

        if arrival_time > window_close:
            penalty_time = (arrival_time - window_close)**2
        elif arrival_time < window_open:
            penalty_time = (window_open - arrival_time) + truck_speed * 0.1  # Slight penalty and advantage to waiting
        else:
            penalty_time = 0  # No penalty if within the time window

        time_cost = arrival_time + penalty_time

        if time_cost < min_time_cost:
            min_time_cost = time_cost
            best_node = i

    if best_node is None:
        return None  # Indicate to wait if no suitable node found
    return best_node

import numpy as np
import heapq

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def distance(point1, point2):
        return np.linalg.norm(point1 - point2)

    def time_to_reach(start, end):
        return distance(start, end) / truck_speed

    def is_within_time_window(arrival_time, window):
        return window[0] <= arrival_time <= window[1]

    reachable_customers = []
    heapq.heapify(reachable_customers)

    for i, customer_pos in enumerate(unvisited_customers):
        travel_time = time_to_reach(cur_truck_pos, customer_pos)
        arrival_time = current_time + travel_time
        time_window = time_windows[i]

        # Priority by start of time window, distance, and if within time window
        if is_within_time_window(arrival_time, time_window):
            urgency = 0
        else:
            urgency = min(abs(arrival_time - time_window[0]), abs(arrival_time - time_window[1]))

        heapq.heappush(reachable_customers, (urgency, travel_time, i))

    # Choose the most urgent customer that can be realistically reached
    while reachable_customers:
        _, _, customer_index = heapq.heappop(reachable_customers)
        estimated_arrival = current_time + time_to_reach(cur_truck_pos, unvisited_customers[customer_index])
        if is_within_time_window(estimated_arrival, time_windows[customer_index]):
            best_node = customer_index
            break
    else:
        best_node = None  # No viable customer could be reached: better wait at current position

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_travel_time(p1, p2):
        return np.linalg.norm(p2 - p1) / truck_speed

    def time_window_penalty(visit_time, time_window):
        start, end = time_window
        if visit_time < start:
            return start - visit_time
        elif visit_time > end:
            return (visit_time - end) * 10  # Penalize heavily if time window is missed
        else:
            return 0

    best_cost = float('inf')
    best_node = None

    for index, customer in enumerate(unvisited_customers):
        travel_time = calculate_travel_time(cur_truck_pos, customer)
        arrival_time = current_time + travel_time
        penalty = time_window_penalty(arrival_time, time_windows[index])
        cost = travel_time + penalty

        if cost < best_cost:
            best_cost = cost
            best_node = index

    return best_node
